        definitions.add(line("WEB034_BULK_ENDPOINT_WITHOUT_LIMIT", Severity.MAJOR, JAVA_MAIN, Set.of("bulk", "List<"), "Bulk endpoint should limit request size", "Bulk APIs can cause memory and transaction pressure if unbounded.", "Add maximum item count validation and document limits.").inPaths("/controller/"));
        definitions.add(line("WEB035_LIST_RESPONSE_WITHOUT_PAGINATION", Severity.MAJOR, JAVA_MAIN, Set.of("List<"), "List response may need pagination", "Unbounded list endpoints can become production bottlenecks.", "Use Page/Slice/cursor responses or explicit limits for large collections.").inPaths("/controller/"));
        definitions.add(line("WEB036_PAGE_ENTITY_EXPOSED", Severity.MAJOR, JAVA_MAIN, Set.of("Page<", "Entity"), "Page<Entity> exposed directly", "Page<Entity> leaks persistence types and paging metadata directly to clients.", "Map Page<Entity> to Page<DTO> or a stable response wrapper.").inPaths("/controller/"));
        definitions.add(line("WEB037_PAGEABLE_WITHOUT_LIMIT", Severity.MAJOR, JAVA_MAIN, Set.of("Pageable"), "Pageable should enforce size limits", "Unrestricted Pageable allows clients to request excessive page sizes.", "Configure max page size and validate/default Pageable inputs.").inPaths("/controller/"));
