        definitions.add(line("BAT019_ALLOW_START_IF_COMPLETE_ON_STEP", Severity.MAJOR, JAVA_MAIN, Set.of("allowStartIfComplete(true)"), "Step riavviabile anche se già completato", "allowStartIfComplete(true) può rieseguire uno step già completato e richiede idempotenza esplicita.", "Usalo solo quando lo step è davvero idempotente e documenta la strategia di riavvio."));
